examples.code:
package main

import (
	"fmt"

	"github.com/malcolmston/chalk"
)

func main() {
	chalk.SetLevel(chalk.LevelBasic)
	defer chalk.ResetDetection()

	styled := chalk.Green("ok")
	fmt.Printf("%q\n", styled)
	fmt.Printf("%q\n", chalk.Strip(styled))
}

