package main

import (
	"fmt"
	"strings"

	"github.com/malcolmston/chalk/figlet"
)

func main() {
	banner := figlet.Render("Hi")
	for _, line := range strings.Split(banner, "\n") {
		fmt.Println(strings.TrimRight(line, " "))
	}
}

package main

import (
	"fmt"
	"strings"

	"github.com/malcolmston/chalk/figlet"
)

func main() {
	banner, err := figlet.RenderFont("banner", "Go")
	if err != nil {
		fmt.Println("error:", err)
		return
	}
	fmt.Println(strings.Count(banner, "\n") + 1)
}

types.signature:
type Choice struct {
	// Name is the label shown to the user.
	Name string
	// Value is an arbitrary value associated with the choice (defaults to Name
	// when nil).
	Value any
	// Disabled marks the choice as unselectable.
	Disabled bool
	// Checked pre-selects the choice in a MultiSelect.
	Checked bool
}

type ConfirmConfig struct {
	// Message is the question shown to the user.
	Message string
	// Default is the answer used when the user submits an empty line.
	Default bool
	// In is the input source (defaults to os.Stdin).
	In io.Reader
	// Out is the output destination (defaults to os.Stdout).
	Out io.Writer
}

type InputConfig struct {
	// Message is the question shown to the user.
	Message string
	// Default is returned when the user submits an empty line.
	Default string
	// Validate, when set, must return nil to accept the input; a non-nil error
	// re-prompts with the error message.
	Validate func(string) error
	// Transform, when set, post-processes the accepted value before it is returned.
	Transform func(string) string
	// In is the input source (defaults to os.Stdin).
	In io.Reader
	// Out is the output destination (defaults to os.Stdout).
	Out io.Writer
}

type MultiSelectConfig struct {
	// Message is the question shown to the user.
	Message string
	// Choices are the selectable options.
	Choices []Choice
	// In is the input source (defaults to os.Stdin).
	In io.Reader
	// Out is the output destination (defaults to os.Stdout).
	Out io.Writer
}

type NumberConfig struct {
	// Message is the question shown to the user.
	Message string
	// Default, when non-nil, is returned for an empty line.
	Default *float64
	// Min, when non-nil, is the inclusive lower bound.
	Min *float64
	// Max, when non-nil, is the inclusive upper bound.
	Max *float64
	// Integer requires the value to be a whole number.
	Integer bool
	// Validate, when set, is an extra check applied to the parsed value.
	Validate func(float64) error
	// In is the input source (defaults to os.Stdin).
	In io.Reader
	// Out is the output destination (defaults to os.Stdout).
	Out io.Writer
}

type PasswordConfig struct {
	// Message is the question shown to the user.
	Message string
	// Validate, when set, must return nil to accept the input; a non-nil error
	// re-prompts with the error message.
	Validate func(string) error
	// Mask, when non-zero, echoes this rune for each character; when zero the
	// input is hidden entirely.
	Mask rune
	// In is the input source (defaults to os.Stdin).
	In io.Reader
	// Out is the output destination (defaults to os.Stdout).
	Out io.Writer
}

type SelectConfig struct {
	// Message is the question shown to the user.
	Message string
	// Choices are the selectable options.
	Choices []Choice
	// Default is the initially highlighted index.
	Default int
	// In is the input source (defaults to os.Stdin).
	In io.Reader
	// Out is the output destination (defaults to os.Stdout).
	Out io.Writer
}

examples.code:
package main

import (
	"bytes"
	"fmt"
	"strings"

	"github.com/malcolmston/chalk/prompts"
)

func main() {
	ok, err := prompts.Confirm(prompts.ConfirmConfig{
		Message: "Continue?",
		Default: false,
		In:      strings.NewReader("y\r"),
		Out:     &bytes.Buffer{},
	})
	if err != nil {
		fmt.Println("error:", err)
		return
	}
	fmt.Println(ok)
}

package main

import (
	"bytes"
	"fmt"
	"strings"

	"github.com/malcolmston/chalk/prompts"
)

func main() {
	answer, err := prompts.Input(prompts.InputConfig{
		Message: "Your name?",
		In:      strings.NewReader("Ada\r"),
		Out:     &bytes.Buffer{},
	})
	if err != nil {
		fmt.Println("error:", err)
		return
	}
	fmt.Printf("got %q\n", answer)
}
